package com.welltrack.identity.security; import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.*; import org.springframework.security.core.context.*; import org.springframework.security.authentication.*; import org.springframework.stereotype.Component; @Component public class JwtFilter extends OncePerRequestFilter{ private final JwtUtil jwt; public JwtFilter(JwtUtil j){this.jwt=j;} protected void doFilterInternal(HttpServletRequest r,HttpServletResponse s,FilterChain c)throws ServletException,IOException{ String h=r.getHeader("Authorization"); if(h!=null&&h.startsWith("Bearer ")){ SecurityContextHolder.getContext().setAuthentication(new UsernamePasswordAuthenticationToken(jwt.gen(h),null,null)); } c.doFilter(r,s);} }